def require_oauth(*scopes):
    """
    Decorator that protects an endpoint by requiring a valid OAuth 2.0 access token.

    Usage:
        @require_oauth()                  # just require a valid token
        @require_oauth('read')            # require 'read' scope
        @require_oauth('read', 'write')   # require both scopes
    """
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            token = extract_bearer_token()
            if not token:
                return jsonify({
                    'error': 'missing_token',
                    'error_description': 'An access token is required to access this resource.',
                }), 401

            token_info = validate_token(token, required_scopes=scopes if scopes else None)
            if token_info is None:
                return jsonify({
                    'error': 'invalid_token',
                    'error_description': 'The access token is invalid, expired, revoked, or lacks required scopes.',
                }), 401

            # Store token info in Flask's g object so the endpoint can use it
            g.oauth_token = token_info
            g.client_id = token_info['client_id']
            g.client_name = token_info['client_name']
            g.scopes = token_info['scopes']

            return f(*args, **kwargs)
        return decorated_function
    return decorator


