@app.route('/oauth/token', methods=['POST'])
def issue_token():
    """
    Issue an access token using client_credentials grant.

    Expects form-encoded or JSON body:
        grant_type=client_credentials
        client_id=...
        client_secret=...
        scope=... (optional, space-separated)
    """
    if request.is_json:
        data = request.get_json()
    else:
        data = request.form.to_dict()

    grant_type = data.get('grant_type')
    client_id = data.get('client_id')
    client_secret = data.get('client_secret')
    requested_scope = data.get('scope', '')

    if grant_type != 'client_credentials':
        return jsonify({
            'error': 'unsupported_grant_type',
            'error_description': 'Only client_credentials grant type is supported.',
        }), 400

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'client_id and client_secret are required.',
        }), 400

    db = get_db()
    client = db.execute(
        "SELECT * FROM clients WHERE client_id = ? AND is_active = 1",
        (client_id,)
    ).fetchone()

    if client is None:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client authentication failed.',
        }), 401

    # Verify client secret
    secret_hash = hash_token(client_secret)
    if secret_hash != client['client_secret_hash']:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client authentication failed.',
        }), 401

    # Validate requested scopes against allowed scopes
    allowed_scopes = set(client['allowed_scopes'].split()) if client['allowed_scopes'] else set()
    requested_scopes = set(requested_scope.split()) if requested_scope else allowed_scopes

    if not requested_scopes.issubset(allowed_scopes):
        return jsonify({
            'error': 'invalid_scope',
            'error_description': f'Requested scopes exceed allowed scopes. Allowed: {" ".join(allowed_scopes)}',
        }), 400

    # Generate and store token
    raw_token = generate_token()
    token_h = hash_token(raw_token)
    expiry_hours = app.config['TOKEN_EXPIRY_HOURS']
    expires_at = datetime.now(timezone.utc) + timedelta(hours=expiry_hours)

    db.execute("""
        INSERT INTO access_tokens (token_hash, client_id, scopes, expires_at)
        VALUES (?, ?, ?, ?)
    """, (token_h, client_id, ' '.join(requested_scopes), expires_at.isoformat()))
    db.commit()

    return jsonify({
        'access_token': raw_token,
        'token_type': 'Bearer',
        'expires_in': expiry_hours * 3600,
        'scope': ' '.join(requested_scopes),
    }), 200


